{{-- Department Sidebar Component --}}
@php
    $search = request('search', '');
    $selectedDepartmentCode = request()->segment(2); // Get code from URL like /departments/fin
    
    // Filter departments based on search
    $filteredDepartments = $departments;
    if (!empty($search)) {
        $filteredDepartments = $departments->filter(function($department) use ($search) {
            $statusLabel = $department->status === 'active' ? 'Active' : 'Inactive';
            
            return stripos($department->name, $search) !== false ||
                   stripos($department->code, $search) !== false ||
                   stripos($department->description, $search) !== false ||
                   stripos($statusLabel, $search) !== false ||
                   ($department->manager && stripos($department->manager->name, $search) !== false);
        });
    }
@endphp

